#include <cuda_runtime.h>
#include <cstdio>
#include <cstdint>
#include <cstddef>
#include <cstdlib>
#include <algorithm>
#include <cstring>

// Linear Congruential Generator for random permutation
static uint32_t lcg(uint32_t& seed) {
    seed = seed * 1664525u + 1013904223u;
    return seed;
}

// Create a random permutation of indices for pointer chasing
static void create_random_permutation(uint32_t* indices, size_t size, uint32_t seed) {
    // Initialize with identity permutation
    for (size_t i = 0; i < size; i++) {
        indices[i] = static_cast<uint32_t>(i);
    }

    // Fisher-Yates shuffle
    for (size_t i = size - 1; i > 0; i--) {
        uint32_t j = lcg(seed) % (i + 1);
        uint32_t temp = indices[i];
        indices[i] = indices[j];
        indices[j] = temp;
    }
}

// Null kernel to measure launch overhead
__global__ void null_kernel() {
    // Do nothing
}

// DRAM latency measurement kernel - pointer chasing
__global__ void measure_dram_latency(volatile uint32_t* indices, uint64_t* cycles, size_t num_accesses) {
    if (threadIdx.x != 0 || blockIdx.x != 0) return;  // Single thread only

    uint32_t idx = 0;

    // Compiler barrier before timing
    asm volatile("" : : : "memory");

    // Start timing
    volatile uint64_t start = clock64();

    // Pointer chasing loop with serial dependency
    #pragma unroll 1
    for (uint64_t i = 0; i < num_accesses; i++) {
        idx = indices[idx];
    }

    // End timing
    volatile uint64_t end = clock64();

    // Compiler barrier after timing
    asm volatile("" : : : "memory");

    // Anti-optimization: consume the result
    volatile uint64_t sink64 = (uint64_t)idx;
    asm volatile("" : "+l"(sink64) : : "memory");

    // Calculate average cycles per access
    *cycles = (end - start) / num_accesses;
}

int main() {
    const size_t ARRAY_SIZE = 32 * 1024 * 1024;  // 32M elements = 128 MB
    const size_t NUM_ACCESSES = 1000000;  // 1M pointer chases
    const int NUM_TRIALS = 3;

    uint64_t results[NUM_TRIALS];

    // Allocate device memory for indices
    uint32_t* d_indices;
    cudaMalloc(&d_indices, ARRAY_SIZE * sizeof(uint32_t));

    // Allocate host memory for indices
    uint32_t* h_indices = (uint32_t*)malloc(ARRAY_SIZE * sizeof(uint32_t));

    // Allocate device memory for result
    uint64_t* d_cycles;
    cudaMalloc(&d_cycles, sizeof(uint64_t));

    // Measure kernel launch overhead
    null_kernel<<<1, 1>>>();
    cudaDeviceSynchronize();

    // Run multiple trials
    for (int trial = 0; trial < NUM_TRIALS; trial++) {
        // Create random permutation
        uint32_t seed = 123456789u + trial;
        create_random_permutation(h_indices, ARRAY_SIZE, seed);

        // Copy to device
        cudaMemcpy(d_indices, h_indices, ARRAY_SIZE * sizeof(uint32_t), cudaMemcpyHostToDevice);

        // Launch kernel
        measure_dram_latency<<<1, 1>>>(d_indices, d_cycles, NUM_ACCESSES);
        cudaDeviceSynchronize();

        // Read result
        cudaMemcpy(&results[trial], d_cycles, sizeof(uint64_t), cudaMemcpyDeviceToHost);
    }

    // Calculate median
    std::sort(results, results + NUM_TRIALS);
    uint64_t median_latency = results[NUM_TRIALS / 2];

    // Output result
    printf("dram_latency_cycles: %lu\n", median_latency);

    // Cleanup
    free(h_indices);
    cudaFree(d_indices);
    cudaFree(d_cycles);

    return 0;
}

#include <cuda_runtime.h>
#include <cstdio>
#include <cstdint>
#include <cstddef>
#include <cstdlib>
#include <algorithm>
#include <cstring>
#include <vector>

__global__ void cache_access_kernel(volatile uint32_t* data, size_t size, size_t iterations, uint64_t* cycles) {
    if (threadIdx.x != 0 || blockIdx.x != 0) return;

    size_t idx = 0;
    size_t stride = 1;

    asm volatile("" : : : "memory");
    volatile uint64_t start = clock64();
    #pragma unroll 1
    for (size_t i = 0; i < iterations; i++) {
        idx = (idx + stride) % (size / sizeof(uint32_t));
        data[idx] = data[idx] + 1;
    }
    volatile uint64_t end = clock64();
    asm volatile("" : : : "memory");

    volatile uint64_t sink64 = (uint64_t)data[idx];
    asm volatile("" : "+l"(sink64) : : "memory");

    *cycles = end - start;
}

int main() {
    volatile uint32_t* d_data;
    uint64_t* d_cycles;

    // Test sizes from 1KB to 128MB (power of 2 steps)
    std::vector<size_t> test_sizes;
    for (size_t size = 1024; size <= 128 * 1024 * 1024; size *= 2) {
        test_sizes.push_back(size);
    }

    std::vector<double> latencies;

    for (size_t size : test_sizes) {
        if (size > 256 * 1024 * 1024) break; // Limit to avoid OOM

        cudaMalloc(&d_data, size);
        cudaMalloc(&d_cycles, sizeof(uint64_t));

        // Initialize data
        cudaMemset((void*)d_data, 0, size);

        // Warm up
        cache_access_kernel<<<1, 1>>>((volatile uint32_t*)d_data, size, 1000, d_cycles);
        cudaDeviceSynchronize();

        // Measure
        const size_t iterations = 1000000;
        cache_access_kernel<<<1, 1>>>((volatile uint32_t*)d_data, size, iterations, d_cycles);
        cudaDeviceSynchronize();

        uint64_t cycles;
        cudaMemcpy(&cycles, (void*)d_cycles, sizeof(uint64_t), cudaMemcpyDeviceToHost);

        double latency_per_access = (double)cycles / iterations;
        latencies.push_back(latency_per_access);

        cudaFree((void*)d_data);
        cudaFree(d_cycles);
    }

    // Find cache cliff: first point where latency increases >20%
    double baseline = latencies[0];
    size_t cache_size_bytes = test_sizes[0];

    for (size_t i = 1; i < latencies.size(); i++) {
        double increase = (latencies[i] - baseline) / baseline;
        if (increase > 0.20) {
            cache_size_bytes = test_sizes[i-1];
            break;
        }
        baseline = latencies[i];
    }

    double cache_size_mb = cache_size_bytes / (1024.0 * 1024.0);
    printf("l2_cache_size_mb: %.1f\n", cache_size_mb);

    return 0;
}

#include <cuda_runtime.h>
#include <cstdio>
#include <cstdint>
#include <cstddef>
#include <cstdlib>
#include <algorithm>
#include <cstring>

__global__ void measure_boost_clock(uint64_t* cycle_counts, size_t iterations_per_thread) {
    if (threadIdx.x == 0 && blockIdx.x == 0) {
        asm volatile("" : : : "memory");
    }

    volatile uint64_t start_cycle = clock64();

    // Compute-intensive loop: 100M FMA operations
    float a = 1.0f, b = 1.0f, c = 0.0f;
    #pragma unroll 1
    for (uint64_t i = 0; i < iterations_per_thread; i++) {
        c = a * b + c;
        a = c * b + a;
        b = a * c + b;
    }

    volatile uint64_t end_cycle = clock64();

    // Anti-optimization sink
    volatile float sink_float = c;
    asm volatile("" : "+f"(sink_float) : : "memory");

    if (threadIdx.x == 0 && blockIdx.x == 0) {
        cycle_counts[0] = start_cycle;
        cycle_counts[1] = end_cycle;
    }
}

int main() {
    const size_t iterations_per_thread = 100000000ULL; // 100M iterations
    const int num_blocks = 32;
    const int threads_per_block = 1024;

    uint64_t* d_cycle_counts;
    cudaMalloc(&d_cycle_counts, 2 * sizeof(uint64_t));

    // Create events for timing
    cudaEvent_t start_event, stop_event;
    cudaEventCreate(&start_event);
    cudaEventCreate(&stop_event);

    // Warm up
    measure_boost_clock<<<1, 1>>>(d_cycle_counts, 1000);
    cudaDeviceSynchronize();

    // Actual measurement
    cudaEventRecord(start_event);
    measure_boost_clock<<<num_blocks, threads_per_block>>>(d_cycle_counts, iterations_per_thread);
    cudaEventRecord(stop_event);
    cudaEventSynchronize(stop_event);

    float wall_clock_ms;
    cudaEventElapsedTime(&wall_clock_ms, start_event, stop_event);

    uint64_t h_cycle_counts[2];
    cudaMemcpy(h_cycle_counts, d_cycle_counts, 2 * sizeof(uint64_t), cudaMemcpyDeviceToHost);

    uint64_t gpu_cycles = h_cycle_counts[1] - h_cycle_counts[0];
    double wall_clock_seconds = wall_clock_ms / 1000.0;

    double frequency_hz = gpu_cycles / wall_clock_seconds;
    double frequency_mhz = frequency_hz / 1000000.0;

    printf("actual_boost_clock_mhz: %.0f\n", frequency_mhz);

    // Cleanup
    cudaFree(d_cycle_counts);
    cudaEventDestroy(start_event);
    cudaEventDestroy(stop_event);

    return 0;
}

#include <cuda_runtime.h>
#include <cstdio>
#include <cstdint>
#include <cstddef>
#include <cstdlib>
#include <algorithm>
#include <cstring>
#include <vector>

__global__ void l2_cache_test(volatile uint32_t* data, size_t size, uint64_t* cycles) {
    if (threadIdx.x != 0 || blockIdx.x != 0) return;

    size_t num_elements = size / sizeof(uint32_t);
    size_t stride = 1;

    asm volatile("" : : : "memory");
    volatile uint64_t start = clock64();
    #pragma unroll 1
    for (size_t i = 0; i < num_elements; i += stride) {
        volatile uint32_t value = data[i];
        asm volatile("" : : "r"(value) : "memory");
    }
    volatile uint64_t end = clock64();
    asm volatile("" : : : "memory");

    *cycles = end - start;
}

int main() {
    const size_t MAX_SIZE = 128 * 1024 * 1024; // 128 MB
    const size_t MIN_SIZE = 1024; // 1 KB

    uint32_t* d_data;
    cudaMalloc(&d_data, MAX_SIZE);

    // Initialize with sequential pattern
    std::vector<uint32_t> h_data(MAX_SIZE / sizeof(uint32_t));
    for (size_t i = 0; i < h_data.size(); i++) {
        h_data[i] = i;
    }
    cudaMemcpy(d_data, h_data.data(), MAX_SIZE, cudaMemcpyHostToDevice);

    std::vector<double> latencies;
    std::vector<size_t> sizes;

    // Sweep from small to large
    for (size_t size = MIN_SIZE; size <= MAX_SIZE; size *= 2) {
        uint64_t* d_cycles;
        cudaMalloc(&d_cycles, sizeof(uint64_t));

        l2_cache_test<<<1, 1>>>(d_data, size, d_cycles);
        cudaDeviceSynchronize();

        uint64_t cycles;
        cudaMemcpy(&cycles, d_cycles, sizeof(uint64_t), cudaMemcpyDeviceToHost);

        size_t num_elements = size / sizeof(uint32_t);
        double cycles_per_access = (double)cycles / num_elements;

        latencies.push_back(cycles_per_access);
        sizes.push_back(size / (1024*1024)); // MB

        cudaFree(d_cycles);
    }

    // Find cache cliff (where latency increases > 50% from min)
    double min_latency = *std::min_element(latencies.begin(), latencies.end());
    size_t cache_size_mb = 0;

    for (size_t i = 0; i < latencies.size(); i++) {
        if (latencies[i] > min_latency * 1.5) {
            cache_size_mb = sizes[i-1]; // Previous size was last within cache
            break;
        }
    }

    if (cache_size_mb == 0 && !latencies.empty()) {
        cache_size_mb = sizes.back(); // All fits in cache
    }

    printf("l2_cache_size_mb: %zu\n", cache_size_mb);

    cudaFree(d_data);
    return 0;
}
